  cursor: pointer;
  background-color: #4458c3;
  color: white;
  border: none;
  border-radius: 4px;
}

.room-status-wrapper {
  display: flex;
  justify-content: space-between;
  align-items: end;
  margin-top: 8px;
}

.remove-room {
  background-color: #e74c3c;
  color: white;
  border: none;
  padding: 4px 8px;
  border-radius: 4px;
  cursor: pointer;
}

.remove-room:hover {
  background-color: #c0392b;
}

.toast.show {
  visibility: visible;
  opacity: 1;
}

.rooms-panel {
  display: flex;
  justify-content: space-between;
  flex-direction: column;
  align-items: end;
  padding-top: 20px;
  background-color: #ffffff;
  border-radius: 8px;
}

.ac-toggle-switch {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  cursor: pointer;
  user-select: none;
  margin-right: 30px;
}

.ac-toggle-switch input[type="checkbox"] {
  display: none;
}

.ac-toggle-switch .slider {
  position: relative;
  width: 50px;
  height: 24px;
  background-color: #ccc;
  border-radius: 34px;
  transition: background-color 0.3s;
}

.ac-toggle-switch .slider::before {
  content: "";
  position: absolute;
  height: 18px;
  width: 18px;
  left: 3px;
  top: 3px;
  background-color: white;
  border-radius: 50%;
  transition: transform 0.3s;
}

.ac-toggle-switch input[type="checkbox"]:checked + .slider {
  background-color: var(--warm-red);
}

.ac-toggle-switch input[type="checkbox"]:checked + .slider::before {
  transform: translateX(26px);
}

.ac-toggle-switch .label-text {
  font-size: 1rem;
}

.pagination-container {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 12px;
  margin: 12px auto 18px auto; 
  font-family: 'Segoe UI', sans-serif;
  text-align: center;
}

.pagination-button {
  border: none;
  color: black;
  cursor: pointer;
  background-color: transparent;
  font-size: 16px;
  font-weight: bold;
  transition: background-color 0.2s;
}

.pagination-button:hover:not(:disabled) {
  color: var(--text-primary);
  font-weight: bold;
}

.pagination-button:disabled {
  color: var(--text-secondary);
  cursor: not-allowed;
}

.pagination-indicator {
  font-weight: bold;
  font-size: 14px;
  color: #333;
}

.modal {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0,0,0,0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.modal.hidden {
  display: none;
}

.modal-content {
  background: #2a2a2e;
  padding: 10px;
  border-radius: 8px;
  width: 80%;
  max-width: 350px;
  color: #d9d9d9;
}

.close-modal {
  position: absolute;
  right: 20px;
  top: 10px;
  font-size: 24px;
  cursor: pointer;
}
